Write-Host "[*] Checking and fixing Node.js and CLI tools..." -ForegroundColor Cyan; $nodeInstalled = Get-Command node -ErrorAction SilentlyContinue; $npmInstalled = Get-Command npm -ErrorAction SilentlyContinue; if (-not $nodeInstalled) { Write-Host "[*] Installing Node.js LTS v22.20.0..." -ForegroundColor Yellow; winget uninstall OpenJS.NodeJS --silent 2>$null; winget install OpenJS.NodeJS.LTS --version 22.20.0 --accept-package-agreements --accept-source-agreements --silent; Start-Sleep -Seconds 3; $env:PATH = [Environment]::GetEnvironmentVariable('PATH', 'Machine') + ';' + [Environment]::GetEnvironmentVariable('PATH', 'User') } else { Write-Host "[OK] Node.js already installed - skipping" -ForegroundColor Green }; if (-not $npmInstalled) { Write-Host "[!] npm not found. Please restart your terminal after Node.js installation." -ForegroundColor Red; exit 1 }; $claudeInstalled = Get-Command claude-code -ErrorAction SilentlyContinue; if (-not $claudeInstalled) { Write-Host "[*] Installing Claude Code..." -ForegroundColor Yellow; & "C:\Program Files\nodejs\npm.cmd" install -g @anthropic-ai/claude-code@latest 2>$null } else { Write-Host "[OK] Claude Code already installed - skipping" -ForegroundColor Green }; $qwenInstalled = Get-Command qwen-code -ErrorAction SilentlyContinue; if (-not $qwenInstalled) { Write-Host "[*] Installing Qwen Code..." -ForegroundColor Yellow; & "C:\Program Files\nodejs\npm.cmd" install -g @qwen-code/qwen-code@latest 2>$null } else { Write-Host "[OK] Qwen Code already installed - skipping" -ForegroundColor Green }; $geminiInstalled = Get-Command gemini -ErrorAction SilentlyContinue; if (-not $geminiInstalled) { Write-Host "[*] Installing Gemini CLI..." -ForegroundColor Yellow; & "C:\Program Files\nodejs\npm.cmd" install -g @google/gemini-cli@latest 2>$null } else { Write-Host "[OK] Gemini CLI already installed - skipping" -ForegroundColor Green }; $copilotInstalled = Get-Command github-copilot-cli -ErrorAction SilentlyContinue; if (-not $copilotInstalled) { Write-Host "[*] Installing GitHub Copilot CLI..." -ForegroundColor Yellow; npm install -g @github/copilot --no-audit --no-fund 2>$null; $npmBin = (npm bin -g); if ($env:PATH -notlike "*$npmBin*") { [Environment]::SetEnvironmentVariable("Path", $env:Path + ";" + $npmBin, [System.EnvironmentVariableTarget]::Machine); $env:Path += ";" + $npmBin; Write-Host "[*] Added npm global bin path to system PATH: $npmBin" -ForegroundColor Yellow } } else { Write-Host "[OK] GitHub Copilot CLI already installed - skipping" -ForegroundColor Green }; Write-Host "[*] Setting up acli and rovodev (forced reinstall)..." -ForegroundColor Cyan; Invoke-WebRequest -Uri https://acli.atlassian.com/windows/latest/acli_windows_amd64/acli.exe -OutFile "$env:USERPROFILE\acli.exe"; $env:PATH += ";$env:USERPROFILE"; [Environment]::SetEnvironmentVariable("PATH", $env:PATH, "User"); echo 'ATATT3xFfGF0qSsOObJuTKcDC9_hhMtzRAVw3Gh_ncv9qZHU5UA7zn9iWQkCrY3tcRXcESdg-P5sdyh4fR5-WFEedanVu4pCNC4LQcTzh-7gJc_iT9rnSQv_NM-_PFVh5xhlKkKfla7c25Kawzlcc58Sx3ysdoCOnxCs26JJq96gbi7bhLz2b_o=A1CE43FC' | & "$env:USERPROFILE\acli.exe" rovodev auth login --email 'mishaelovsky5@gmail.com' --token; Write-Host ""; Write-Host "[*] Verifying acli rovodev authentication..." -ForegroundColor Cyan; & "$env:USERPROFILE\acli.exe" rovodev auth status; Write-Host ""; Write-Host "[OK] SUCCESS! Testing installations:" -ForegroundColor Green; & "C:\Program Files\nodejs\node.exe" --version 2>$null; & "C:\Program Files\nodejs\node.exe" "C:\Users\micha\AppData\Roaming\npm\node_modules\@anthropic-ai\claude-code\cli.js" --version 2>$null; if (Test-Path "$env:USERPROFILE\acli.exe") { Write-Host "[OK] acli.exe found at: $env:USERPROFILE\acli.exe" -ForegroundColor Green } else { Write-Host "[!] acli.exe not found!" -ForegroundColor Red }; Write-Host ""; Write-Host "[OK] ALL TOOLS VERIFIED! Rovo Dev is authenticated and ready!" -ForegroundColor Green; Write-Host "[!!] You can now use 'rovo' or 'acli rovodev run' commands!" -ForegroundColor Yellow
